#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Compressed SPC workflow GUI launcher.

This file contains the full GUI source compressed so it can be updated through
GitHub's contents API as a single file. Running it executes the same source as
the local development copy.
"""

import base64
import zlib

_SOURCE = """"""
exec(compile(zlib.decompress(base64.b64decode(_SOURCE)).decode("utf-8"), __file__, "exec"))
